changeSet.sql:
CREATE TABLE suppliers ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, code VARCHAR(50) NOT NULL, type VARCHAR(20) NOT NULL DEFAULT 'COMPANY', name VARCHAR(250) NOT NULL, email VARCHAR(150), phone VARCHAR(30), address VARCHAR(500), tax_id VARCHAR(50), payment_terms VARCHAR(100), currency VARCHAR(3) NOT NULL DEFAULT 'MRU', notes VARCHAR(500), credit_limit NUMERIC(19,2) NOT NULL DEFAULT 0, active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_suppliers_tenant_code UNIQUE (tenant_id, code) );
CREATE INDEX idx_suppliers_tenant ON suppliers(tenant_id); CREATE INDEX idx_suppliers_phone ON suppliers(phone);
CREATE TABLE supplier_balances ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, supplier_id UUID NOT NULL, total_invoiced NUMERIC(19,2) NOT NULL DEFAULT 0, total_paid NUMERIC(19,2) NOT NULL DEFAULT 0, balance NUMERIC(19,2) NOT NULL DEFAULT 0, last_payment_date DATE, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_supplier_balances_supplier UNIQUE (tenant_id, supplier_id) );
CREATE INDEX idx_supplier_balances_tenant ON supplier_balances(tenant_id);

DO $$
DECLARE
    t text;
    tables text[] := ARRAY['suppliers', 'supplier_balances'];
BEGIN
    FOREACH t IN ARRAY tables LOOP
        EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', t);
        EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY', t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_select ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_select ON %I
                FOR SELECT
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_modify ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_modify ON %I
                FOR ALL
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)
                WITH CHECK (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);
    END LOOP;
END
$$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'hisaberp_app') THEN
        GRANT ALL ON TABLE suppliers, supplier_balances TO hisaberp_app;
    END IF;
END $$;
